sql:
SELECT * 
FROM drinks
WHERE country_of_origin IN ('USA', 'Canada') AND abv > 40;

SELECT sale_id, drink_id, quantity_sold, sale_date, sales_channel, customer_id, discount_applied, total_revenue, is_returned
FROM sales
WHERE customer_id = 1;

SELECT drink_type, MIN(abv) AS min_abv
FROM drinks
GROUP BY drink_type;

SELECT COUNT(*) 
FROM drinks 
WHERE drink_type = 'Soft Drink' AND shelf_life > 1825;

SELECT drink_id, drink_name 
FROM drinks 
WHERE abv = (SELECT MAX(abv) FROM drinks);

SELECT u.username, u.role
FROM users u
INNER JOIN suppliers s ON u.username = s.supplier_name;

SELECT MIN(production_cost) 
FROM drinks 
WHERE abv > 20;

external_knowledge:
- Profit margin is calculated as (retail price - production cost);
- The term "alcoholic ingredients" refers to the alcohol used in the preparation of the drinks;
- Supplier details include the supplier's name, contact information, and performance rating.

sql:
SELECT role_name 
FROM roles 
WHERE created_date = (SELECT MAX(created_date) FROM roles);

SELECT SUM(total_revenue) AS total_revenue_last_month
FROM sales
WHERE sale_date >= DATE('now', '-1 month');

SELECT drink_name, retail_price
FROM drinks
WHERE retail_price = (SELECT MAX(retail_price) FROM drinks);

SELECT drink_name, retail_price
FROM drinks
ORDER BY retail_price DESC;
